const t = $('When Executed by Another Workflow').item.json;
const page = $('Lee reserva actual').item.json;
const p = (page && page.properties) || {};

const servicio = p['Servicio']?.select?.name || '';
const vehiculo = p['Vehiculo']?.select?.name || '';
const estado   = p['Estado']?.select?.name || '';
const fecha_actual = p['Fecha']?.date?.start ? String(p['Fecha'].date.start).slice(0, 10) : '';
const nombre   = p['Titulo']?.title?.[0]?.plain_text || '';
const precio   = p['Precio']?.number ?? 0;
const hora_actual = p['Hora recepcion ']?.rich_text?.[0]?.plain_text || '';
const cliente_id = p['👤 Clientes Genten']?.relation?.[0]?.id || null;

function parseFecha(raw) {
  if (!raw) return '';
  raw = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  const d = new Date(raw);
  return isNaN(d) ? '' : d.toISOString().slice(0, 10);
}
function parseHora(raw) {
  if (!raw) return '';
  raw = String(raw).trim();
  if (/^\d{1,2}:\d{2}$/.test(raw)) return raw.padStart(5, '0');
  return raw;
}

const nueva_fecha = parseFecha(t.nueva_fecha);
const nueva_hora  = parseHora(t.nueva_hora);
const mismo_dia   = !!nueva_fecha && nueva_fecha === fecha_actual;

return [{ json: { page_id: t.page_id, nueva_fecha, nueva_hora, servicio, vehiculo, estado, fecha_actual, nombre, mismo_dia, precio, hora_actual, cliente_id } }];

const d = $json;
const c = $('Prepara contexto').item.json;

const esMoto = String(c.vehiculo || '').toLowerCase() === 'moto';
const servicio = String(c.servicio || '').toLowerCase();
const esFullDay = esMoto
  ? servicio.includes('abrillantado de pintura')
  : servicio.includes('completo exterior e interior');

let permitido = true;
let motivo = '';

if (c.estado !== 'Reservado') {
  permitido = false;
  motivo = 'la reserva no está activa, no se puede reagendar';
} else if (!c.nueva_fecha) {
  permitido = false;
  motivo = 'la nueva fecha no es válida';
} else if (c.mismo_dia) {
  permitido = true;
} else if (d.dia_bloqueado_full_day) {
  permitido = false;
  motivo = 'ese día ya tiene reservado un trabajo de día completo';
} else if (esFullDay && (d.total_citas || 0) > 0) {
  permitido = false;
  motivo = 'ese servicio ocupa el día completo y ese día ya tiene reservas';
} else if (esMoto && !d.disponibilidad_motos) {
  permitido = false;
  motivo = 'ya no hay cupo para motos ese día';
} else if (!esMoto && !d.disponibilidad_vehiculos) {
  permitido = false;
  motivo = 'ya no hay cupo para vehículos ese día';
}

return [{ json: { 
  permitido, motivo, 
  page_id: c.page_id, 
  nueva_fecha: c.nueva_fecha, 
  nueva_hora: c.nueva_hora, 
  fecha_actual: c.fecha_actual, 
  servicio: c.servicio, 
  vehiculo: c.vehiculo, 
  nombre: c.nombre,
  precio: c.precio,
  cliente_id: c.cliente_id
} }];

